data.script:
var d = inputs.data;
if (!d.video_url) throw new Error('video_url is required');
if (!d.title) throw new Error('title is required');
var desc = d.description || '';
if (desc.indexOf('#Shorts') === -1) desc += '\n\n#Shorts';
return {
  video_url: d.video_url,
  title: d.title,
  description: desc,
  tags: d.tags || [],
  visibility: d.visibility || 'public',
  category_id: d.category_id || '22'
};

var clientId = getVar('youtube_client_id');
var clientSecret = getVar('youtube_client_secret');
var refreshToken = getVar('youtube_refresh_token');
if (!clientId || !clientSecret || !refreshToken) throw new Error('YouTube OAuth2 credentials not configured');
var body = 'client_id=' + encodeURIComponent(clientId) + '&client_secret=' + encodeURIComponent(clientSecret) + '&refresh_token=' + encodeURIComponent(refreshToken) + '&grant_type=refresh_token';
var resp = httpPost('https://oauth2.googleapis.com/token', body, {'Content-Type': 'application/x-www-form-urlencoded'});
if (resp.status !== 200) throw new Error('Token refresh failed: ' + toString(resp.body));
var data = typeof resp.body === 'string' ? jsonParse(resp.body) : resp.body;
return {access_token: data.access_token, video: inputs.data};
